        self.tokenizer = nltk.word_tokenize

    def get_token_counts(self, text):
        tokens = self.tokenizer(text)
        return {token: tokens.count(token) for token in set(tokens)}

    def prioritize(self, data):
        prioritized_data = {}
        for key, value in data.items():
            token_counts = self.get_token_counts(value['data'])
            value['priority'] = sum(token_counts.values())
            prioritized_data[key] = value
        return prioritized_data

