class TokenBudgetAdjuster:
    def __init__(self, average_complexity, average_urgency):
        self.average_complexity = average_complexity
        self.average_urgency = average_urgency

    def adjust_budget(self, agent_id):
        base_budget = 1024  # Default base budget in tokens
        complexity_factor = self.average_complexity / 5  # Example factor based on average complexity
        urgency_factor = self.average_urgency / 5  # Example factor based on average urgency

        if self.average_complexity > 3:
            complexity_factor *= 1.2  # Increase for higher complexity
        if self.average_urgency > 3:
            urgency_factor *= 1.5  # Increase for higher urgency

        adjusted_budget = base_budget * (complexity_factor + urgency_factor)

        return f"Agent {agent_id} Token Budget: {adjusted_budget:.2f}"

