class TokenAllocator:
    def __init__(self, tokens):
        self.tokens = tokens
        self.tasks = {}

    def add_task(self, task_id, priority):
        if task_id not in self.tasks:
            self.tasks[task_id] = {
                'priority': priority,
                'allocated_tokens': 0
            }

    def allocate_tokens(self):
        total_priority = sum(task['priority'] for task in self.tasks.values())
        for task_id, task_info in self.tasks.items():
            allocation = (task_info['priority'] / total_priority) * self.tokens
            self.tasks[task_id]['allocated_tokens'] = round(allocation)

    def get_task_allocations(self):
        return {task_id: info['allocated_tokens'] for task_id, info in self.tasks.items()}

